def _utc_now_iso():
    return datetime.now(timezone.utc).isoformat()


def _get_credential():
    return DefaultAzureCredential(exclude_interactive_browser_credential=True)


def _get_blob_service_client(credential):
    if BLOB_CONNECTION_SETTING:
        conn = os.getenv(BLOB_CONNECTION_SETTING, "").strip()
        if not conn:
            raise ValueError(f"Env var '{BLOB_CONNECTION_SETTING}' not set or empty.")
        return BlobServiceClient.from_connection_string(conn)
    if not BLOB_SERVICE_URL:
        raise ValueError("Set BLOB_SERVICE_URL (e.g. https://<account>.blob.core.windows.net) or BLOB_CONNECTION_SETTING.")
    return BlobServiceClient(account_url=BLOB_SERVICE_URL, credential=credential)


def _get_cosmos_container(credential):
    if not COSMOS_ENDPOINT:
        raise ValueError("Set COSMOS_ENDPOINT (e.g. https://<account>.documents.azure.com:443/).")
    client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
    db = client.create_database_if_not_exists(id=COSMOS_DATABASE)
    container = db.create_container_if_not_exists(
        id=COSMOS_CONTAINER,
        partition_key=PartitionKey(path="/pk"),
        offer_throughput=int(os.getenv("COSMOS_THROUGHPUT", "400") or "400"),
    )
    return container


